/**
 * Learning Extractor — Classifies text into structured learnings
 *
 * Extracts Decision, ErrorFix, WorkingSolution, and Pattern entries
 * from assistant messages or session data. Used by handoff-writer
 * to structure HANDOFF.md and by pre-compact-saver for knowledge capture.
 *
 * Pure function, no side effects.
 */

export interface Learning {
  type: 'Decision' | 'ErrorFix' | 'WorkingSolution' | 'Pattern';
  content: string;
}

interface PatternRule {
  type: Learning['type'];
  /** Patterns that indicate this learning type (case-insensitive substring match) */
  markers: string[];
}

const RULES: PatternRule[] = [
  {
    type: 'Decision',
    markers: [
      'decided to', 'chose ', 'went with', 'using instead of',
      'switched to', 'picked ', 'settled on', 'opting for',
    ],
  },
  {
    type: 'ErrorFix',
    markers: [
      'fixed by', 'the issue was', 'root cause', 'resolved by',
      'the fix:', 'the problem was', 'bug was', 'error was caused',
      'workaround:', 'the solution was',
    ],
  },
  {
    type: 'WorkingSolution',
    markers: [
      'works by', 'implemented', 'the approach:', 'solution:',
      'created a', 'built a', 'added a', 'wired up',
    ],
  },
  {
    type: 'Pattern',
    markers: [
      'always ', 'never ', 'prefer ', 'avoid ',
      'best practice', 'anti-pattern', 'rule of thumb',
      'important:', 'remember to', 'don\'t forget',
    ],
  },
];

/**
 * Extract learnings from text.
 * Splits text into sentences and classifies each against pattern rules.
 * Returns deduplicated, trimmed results (max 10 per type).
 */
export function extractLearnings(text: string): Learning[] {
  if (!text || text.length < 20) return [];

  const learnings: Learning[] = [];
  const seen = new Set<string>();

  // Split on sentence boundaries (. ! ? or newlines)
  const sentences = text
    .split(/(?<=[.!?\n])\s+/)
    .map(s => s.trim())
    .filter(s => s.length > 15 && s.length < 500);

  for (const sentence of sentences) {
    const lower = sentence.toLowerCase();

    for (const rule of RULES) {
      if (rule.markers.some(m => lower.includes(m))) {
        const key = `${rule.type}:${sentence.substring(0, 60)}`;
        if (!seen.has(key)) {
          seen.add(key);
          learnings.push({ type: rule.type, content: sentence });
        }
        break; // One classification per sentence
      }
    }
  }

  // Cap at 10 per type
  const counts: Record<string, number> = {};
  return learnings.filter(l => {
    counts[l.type] = (counts[l.type] || 0) + 1;
    return counts[l.type] <= 10;
  });
}

/**
 * Format learnings into Markdown sections for HANDOFF.md.
 * Only includes sections that have entries.
 */
export function formatLearnings(learnings: Learning[]): string {
  const sections: string[] = [];

  const grouped: Record<string, string[]> = {};
  for (const l of learnings) {
    if (!grouped[l.type]) grouped[l.type] = [];
    grouped[l.type].push(l.content);
  }

  const headings: Record<string, string> = {
    Decision: 'Decisions Made',
    ErrorFix: 'Issues Fixed',
    WorkingSolution: 'What Was Built',
    Pattern: 'Patterns Noted',
  };

  for (const [type, heading] of Object.entries(headings)) {
    const items = grouped[type];
    if (items && items.length > 0) {
      sections.push(`## ${heading}\n${items.map(i => `- ${i}`).join('\n')}`);
    }
  }

  return sections.join('\n\n');
}
